switch v := x.(type) {
case string:
    // v 的类型？
case int:
    // v 的类型？
}
```

以下代码有什么问题？
```go
func process(err error) {
    if e, ok := err.(*os.PathError); ok {
        fmt.Println(e.Path)
    }
}
// 调用
var p *os.PathError = nil
process(p)
```
